on conflict (employee_email)
do update set employee_id = excluded.employee_id, employee_name = excluded.employee_name, state = excluded.state, designation = excluded.designation, approval_email_level_1 = excluded.approval_email_level_1, approval_email_level_2 = excluded.approval_email_level_2, approval_email_level_3 = excluded.approval_email_level_3;
